  ('353f9fc0-3cfb-4e84-b598-3a78af74939d', 'tallow-skin-first-foundation', 'Tallow Skin-First Foundation', 'Christian Beauty Co.', 'Christian Beauty Co. is an explicitly faith-based clean beauty brand. Their own mission statement states faith calls them to a higher standard where skincare is rooted in values that honor both body and spirit.', 1, ARRAY['https://www.christianbeautyco.com/discernly'], 'https://www.christianbeautyco.com/products/tallow-skin-first-foundation?sca_ref=11765311.nBjYCINV1gor', 'direct', 'Beauty & Makeup', 'https://www.christianbeautyco.com/cdn/shop/files/TallowSkin-FirstFoundation.png?v=1772142676&width=980', NULL, 'christian'),
