insert into associations (product_id, claim_text, source_urls, confidence_tier, theme_tag, date_checked) values
  ('69f81ae9-e14a-42b8-847d-94124a3d5c4a', 'Logo depicts Vulcan, the Roman god of fire and metalworking — confirmed by the company''s own brand history.', ARRAY['https://www.armandhammer.com/en/about-us', 'https://en.wikipedia.org/wiki/Arm_%26_Hammer', 'https://en.wikipedia.org/wiki/Vulcan_(mythology)'], 1, 'roman-mythology', '2026-07-01'),
  ('8a2748c0-a862-4c14-8122-8dfe7dd87a56', 'Founder Emanuel Bronner built the brand around a universalist "All-One-God-Faith" philosophy explicitly blending Judaism, Islam, and Christianity, not centered on Christianity specifically.', ARRAY['https://www.ucpress.edu/blog-posts/how-californias-dr-bronners-spiritual-messaging-became-a-global-brand', 'https://en.wikipedia.org/wiki/Emanuel_Bronner', 'https://info.drbronner.com/all-one-blog/2016/11/whole-crazy-trip-started/'], 1, 'universalist-syncretism', '2026-07-01'),
  ('083fe587-5477-4a9f-bfa1-c762d62d65c1', 'Entire collection is structured as a tarot-style "deck" of named fortune cards (The Illusionist, The Sovereign, The Sage, and more). Each bottle includes a QR code for a "shower reading" and a daily "manifestation." Method''s own product copy reads: "Are you ready to hear your fortune? Shoot for the stars today with a body wash that offers a glimpse into your future." This is scoped to the limited-edition Shower Readings line only — Method''s everyday cleaners carry no such theme and are not flagged.', ARRAY['https://methodproducts.com/pages/shower-readings', 'https://www.ulta.com/p/limited-edition-shower-readings-body-wash-pimprod2052565'], 1, 'fortune-telling', '2026-07-01'),
  ('4fef04ea-018c-41f5-8651-f1e351082572', 'The mascot was deliberately designed as a genie at P&G''s own direction. A 2014 NYT obituary for original illustrator Richard Black quotes P&G''s communications manager: the company wanted "magic from a bottle" represented by a genie, and the artist was directed to draw one. Genies/jinn originate in Arabic and Islamic folklore.', ARRAY['https://en.wikipedia.org/wiki/Mr._Clean'], 1, 'islamic-folklore', '2026-07-01'),
  ('ee31b204-a206-463c-881c-03b64d9b9db8', 'Named after Ajax (Telamonian Ajax), Greek mythological hero of the Trojan War, second in strength only to Achilles. Current marketing leans into it directly: "Stronger than dirt," with copy describing customers as "everyday heroes."', ARRAY['https://en.wikipedia.org/wiki/Ajax_the_Great', 'https://greekcitytimes.com/2022/06/03/hidden-ancient-greek-meaning-behind-ajax-brand-name/'], 1, 'greek-mythology', '2026-07-01'),
  ('9bf704f2-6aaf-4842-a997-9d6ba7377582', 'Directly named after the Greek/Roman hero Hercules. The company''s own current product pages use the line "Behold the power of Hercules, products built to last and trusted by plumbers."', ARRAY['https://www.oatey.com/products/hercules-glug-kitchen-liquid-drain-opener--782826565'], 1, 'greek-mythology', '2026-07-01'),
  ('97d6f3d5-a8d5-4490-9fd0-d3ebc8150678', 'Entire product line is built around named crystals with stated metaphysical properties (rose quartz for "joy," amethyst for "dream state," peridot for "balance and control your thoughts"). Marketing copy: "Call in your crystal super power. Crystal-infused and plant-powered."', ARRAY['https://www.pacificabeauty.com/collections/aromapower', 'https://www.ulta.com/brand/pacifica?category=fragrance'], 1, 'crystal-metaphysics', '2026-07-01'),
  ('2e757b73-31bd-4b0a-ba98-e78f35ccd594', 'Founded by Yogi Bhajan, who introduced Kundalini Yoga to the US; the tea recipe and brand are explicitly built on Ayurvedic philosophy. The company''s own "our story" copy still cites Ayurveda as the foundation.', ARRAY['https://en.wikipedia.org/wiki/Yogi_Tea'], 1, 'ayurvedic', '2026-07-01'),
  ('6d66cd21-f300-4c4f-9d94-d7030e816037', 'Documented marketing campaigns built on witchcraft/occult themes: the company hired a self-described witch doctor in 2019 to publicly "hex" inventory as a Halloween stunt, and sold "sell your soul" branded merchandise with a mock contract for the buyer''s "Eternal Soul." These campaigns themselves are documented fact; describing the brand as "satanic" is contested commentary, not a company statement.', ARRAY['https://www.adweek.com/creativity/drink-at-your-own-risk-liquid-death-hires-witch-doctor-to-hex-its-water/', 'https://www.westernjournal.com/liquid-death-water-brand-offered-buy-customers-souls-even-offers-contract-put-satanic-deal-writing/'], 2, 'occult-marketing', '2026-07-01'),
  ('a7ecf640-9185-4157-be2e-efe6f98f3572', 'Named directly after Gaia, the Greek primordial Earth goddess and mother of all life in Greek mythology. Confirmed by the founder''s own company history (founded 1986/1987 by herbalist Ric Scalzo).', ARRAY['https://www.peoplespharmacy.com/articles/introducing-gaia-herbs'], 1, 'greek-mythology', '2026-07-01'),
  ('cc627cea-271c-40f0-8b47-4a544d23eba2', 'Same brand-wide genie mascot association as Mr. Clean''s All-Purpose Cleaner — P&G''s own communications manager confirmed to the NYT that the mascot was deliberately designed as a genie.', ARRAY['https://en.wikipedia.org/wiki/Mr._Clean'], 1, 'islamic-folklore', '2026-07-01'),
  ('3b568ff4-e3c8-4fc7-abf5-e3cf0d62ff83', 'Same brand-wide genie mascot association as Mr. Clean''s All-Purpose Cleaner.', ARRAY['https://en.wikipedia.org/wiki/Mr._Clean'], 1, 'islamic-folklore', '2026-07-01'),
  ('cf653ca3-b20a-4f03-943c-7aad1c69df3c', 'Brand name is explicitly drawn from an ancient Iroquois Great Law of Peace philosophy. The company''s own website states: "Our name is inspired by an ancient Iroquois philosophy which instructs that in our every deliberation, we must consider the impact of our decisions on the next seven generations."', ARRAY['https://www.seventhgeneration.com/blog/origin-our-name-seventh-generation', 'https://www.fastcompany.com/665006/great-law-iroquois-confederacy'], 1, 'indigenous-philosophy', '2026-07-01'),
  ('3475208e-fd18-4dab-9311-1f5bafbf50c8', 'Logo is a twin-tailed siren from Greek mythology, confirmed on the company''s own "Story of the Siren" page: "it depicted a siren, a seductive twin-tailed mermaid from Greek mythology who enticed passing sailors to their doom with her enchanting song."', ARRAY['https://about.starbucks.com/history/the-story-of-the-siren/'], 1, 'greek-mythology', '2026-07-01'),
  ('44312886-55e1-4ae7-b2bd-f2665e67cd01', 'Name and branding deliberately center on death-themed imagery. The company''s own website states: "To some, a death wish may sound irresponsible, morbid, a step too far — but we believe it is the boldest sign of living life to the fullest." This is secular dark/death-themed branding, not tied to a specific mythology or occult practice.', ARRAY['https://www.forbes.com/sites/forbestreptalks/2016/02/09/meet-the-entrepreneur-behind-the-super-bowl-coffee-ad/', 'https://en.wikipedia.org/wiki/Death_Wish_Coffee'], 1, 'secular-death-themed', '2026-07-01'),
  ('a59fb6ef-1ab4-4d2e-8420-f39aa424ff06', 'Founder Jessica Alba publicly shared Instagram content in August 2024 involving occult/spiritual practices (numerology, astrology, crystals, and sage burning). Alba had stepped down as Chief Creative Officer in April 2024, before the posts, so she was no longer a company officer at the time, and the brand''s own products carry no occult imagery or branding. This is the founder''s personal social media activity, not a company branding decision.', ARRAY['https://www.instagram.com/p/C_bp7Qpu-hr/'], 2, 'founder-personal-conduct', '2026-07-01'),
  ('cef642f5-c3ed-4ee8-b56f-019bfa9e9a37', 'Logo depicts Vulcan, the Roman god of fire and metalworking — confirmed by the company''s own brand history. Same brand-wide association as the Arm & Hammer baking soda entry.', ARRAY['https://www.armandhammer.com/en/about-us', 'https://en.wikipedia.org/wiki/Arm_%26_Hammer', 'https://en.wikipedia.org/wiki/Vulcan_(mythology)'], 1, 'roman-mythology', '2026-07-03'),
  ('2a2d5cdb-94a1-41d5-aa67-5f0b71d7da8e', 'Named after Ajax (Telamonian Ajax), the Greek mythological hero of the Trojan War. Same brand-wide association as the Ajax Powder Cleanser entry.', ARRAY['https://en.wikipedia.org/wiki/Ajax_the_Great', 'https://greekcitytimes.com/2022/06/03/hidden-ancient-greek-meaning-behind-ajax-brand-name/'], 1, 'greek-mythology', '2026-07-03'),
  ('e282ebf3-6a19-4d69-997d-75317ecb59b3', 'Brand name is explicitly drawn from an ancient Iroquois Great Law of Peace philosophy. Same brand-wide association as the Seventh Generation Laundry Detergent entry.', ARRAY['https://www.seventhgeneration.com/blog/more-than-a-name', 'https://en.wikipedia.org/wiki/Seventh_Generation_Inc.'], 1, 'indigenous-philosophy', '2026-07-03'),
  ('9d8a976e-741b-433c-89bb-52c8d0ae3c36', 'Named after Nyx, the Greek goddess of the night. Confirmed by founder Toni Ko''s own statements at the brand''s 1999 launch.', ARRAY['https://en.wikipedia.org/wiki/NYX_Cosmetics', 'https://www.allure.com/story/nyx-professional-makeup-founder-toni-ko'], 1, 'greek-mythology', '2026-07-03'),
  ('48755b30-713b-4880-8907-a7e820940e08', 'Founders deliberately built the brand around dark/rebellious aesthetic choices confirmed in their own words. Product lines include "Perversion" mascara, "Vice" palettes, "Naked" palettes, and "Sin" eyeshadow. Co-founders described themselves as "co-conspirators" in published interviews. This is dark aesthetic branding by the founders'' own choice, not a specific mythology or belief-system tie.', ARRAY['https://en.wikipedia.org/wiki/Urban_Decay_(cosmetics)', 'https://www.allure.com/story/urban-decay-history'], 1, 'secular-dark-aesthetic', '2026-07-03'),
  ('feb29ac2-3ad3-4457-94f3-bfc39467ccbd', 'Founder Amanda Chantal Bacon describes the company as "a cosmic beacon" in her own interviews, references astrology and crystal energy throughout the brand''s marketing, and publicly stated of a stolen store crystal, "You do not want the energy of a stolen crystal." Company''s own marketing describes Moon Juice as "a healing force, an etheric potion, a cosmic beacon."', ARRAY['https://www.theguardian.com/lifeandstyle/2015/jan/16/moon-juice-food-for-beautiful-people', 'https://moonjuice.com/pages/about'], 1, 'astrology-crystal-energy', '2026-07-03'),
  ('829645b8-573a-48f1-b52f-725921102065', 'Bottle is a five-pointed star, described in the company''s own marketing as "a celestial bottle: a five-pointed star evoking womanhood, protection and destiny." Company''s own copy calls it "a cosmic object that appears supernaturally out of space" and "the embodiment of dreams."', ARRAY['https://www.mugler.com/en-us/angel', 'https://en.wikipedia.org/wiki/Angel_(fragrance)'], 1, 'celestial-supernatural', '2026-07-03'),
  ('1eb223bc-4cff-4f1f-bba2-8cbd1481c817', 'Named after Venus, the Roman goddess of love and beauty. Company''s own brand platform and tagline: "Reveal the goddess in you." The company''s own brand team confirmed the internal creative platform as "every woman can feel like a goddess."', ARRAY['https://gillette.com/en-us/venus', 'https://en.wikipedia.org/wiki/Gillette_Venus'], 1, 'roman-mythology', '2026-07-03'),
  ('68dd8ad1-ee7a-435e-9eec-dc971b5a6494', 'Named after Nyx, the Greek goddess of the night. Confirmed by founder Toni Ko''s own statements at the brand''s 1999 launch.', ARRAY['https://en.wikipedia.org/wiki/NYX_Cosmetics', 'https://www.allure.com/story/nyx-professional-makeup-founder-toni-ko'], 1, 'greek-mythology', '2026-07-03'),
  ('9f853b38-c4c0-48a5-809b-5322b9a93c02', 'Named after Nyx, the Greek goddess of the night. Confirmed by founder Toni Ko''s own statements at the brand''s 1999 launch.', ARRAY['https://en.wikipedia.org/wiki/NYX_Cosmetics', 'https://www.allure.com/story/nyx-professional-makeup-founder-toni-ko'], 1, 'greek-mythology', '2026-07-03'),
  ('f90b5787-dee6-47ab-ac3a-8b4c185b1d85', 'Named after Nyx, the Greek goddess of the night. Confirmed by founder Toni Ko''s own statements at the brand''s 1999 launch.', ARRAY['https://en.wikipedia.org/wiki/NYX_Cosmetics', 'https://www.allure.com/story/nyx-professional-makeup-founder-toni-ko'], 1, 'greek-mythology', '2026-07-03'),
  ('5f1d1289-8784-4322-945f-0cf21c5237e2', 'Founders deliberately built the brand around dark/rebellious aesthetic choices confirmed in their own words. Product lines include "Perversion" mascara, "Vice" palettes, "Naked" palettes, and "Sin" eyeshadow. Co-founders described themselves as "co-conspirators" in published interviews. This is dark aesthetic branding by the founders'' own choice, not a specific mythology or belief-system tie.', ARRAY['https://en.wikipedia.org/wiki/Urban_Decay_(cosmetics)', 'https://www.allure.com/story/urban-decay-history'], 1, 'secular-dark-aesthetic', '2026-07-03'),
  ('6d0f7e11-f91f-44b8-9a99-502522bf28d9', 'Founders deliberately built the brand around dark/rebellious aesthetic choices confirmed in their own words. Product lines include "Perversion" mascara, "Vice" palettes, "Naked" palettes, and "Sin" eyeshadow. Co-founders described themselves as "co-conspirators" in published interviews. This is dark aesthetic branding by the founders'' own choice, not a specific mythology or belief-system tie.', ARRAY['https://en.wikipedia.org/wiki/Urban_Decay_(cosmetics)', 'https://www.allure.com/story/urban-decay-history'], 1, 'secular-dark-aesthetic', '2026-07-03'),
  ('65189275-4415-4144-b06d-997aab149505', 'Founders deliberately built the brand around dark/rebellious aesthetic choices confirmed in their own words. Product lines include "Perversion" mascara, "Vice" palettes, "Naked" palettes, and "Sin" eyeshadow. Co-founders described themselves as "co-conspirators" in published interviews. This is dark aesthetic branding by the founders'' own choice, not a specific mythology or belief-system tie.', ARRAY['https://en.wikipedia.org/wiki/Urban_Decay_(cosmetics)', 'https://www.allure.com/story/urban-decay-history'], 1, 'secular-dark-aesthetic', '2026-07-03'),
  ('254de363-d53b-4955-b15b-55b5fbf69fa8', 'Entire product line is built around named crystals with stated metaphysical properties (rose quartz for "joy," amethyst for "dream state," peridot for "balance and control your thoughts"). Marketing copy: "Call in your crystal super power. Crystal-infused and plant-powered."', ARRAY['https://www.pacificabeauty.com/collections/aromapower', 'https://www.ulta.com/brand/pacifica?category=fragrance'], 1, 'crystal-metaphysics', '2026-07-01'),
  ('17e7ef32-bd04-41fd-a133-c07852cd1b79', 'Founder Amanda Chantal Bacon describes the company as "a cosmic beacon" in her own interviews, references astrology and crystal energy throughout the brand''s marketing, and publicly stated of a stolen store crystal, "You do not want the energy of a stolen crystal." Company''s own marketing describes Moon Juice as "a healing force, an etheric potion, a cosmic beacon."', ARRAY['https://www.theguardian.com/lifeandstyle/2015/jan/16/moon-juice-food-for-beautiful-people', 'https://moonjuice.com/pages/about'], 1, 'astrology-crystal-energy', '2026-07-03');
